#include<bits/stdc++.h>
using namespace std;
struct node{
	int a,b,c;
}d[100001];
int main()
{
	int n,i,j,sum=0;
	scanf("%d",&n);
	for(i=1;i<=n;i++)
	{
		scanf("%d%d%d",&d[i].a,&d[i].b,&d[i].c);
	}
	for(j=1;j<=n;j++)
	{
		sum=d[j].b*7+d[j].c*3;
		if(d[j].b+d[j].c>140&&sum>=800)
		{
			printf("Excellent\n");
		}
		else
		{
			printf("Not excellent\n");
		}
	}
	return 0;
}
